  `scrap_id` bigint NOT NULL AUTO_INCREMENT,
  `scrap_code` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '报废单号',
  `status` int DEFAULT NULL COMMENT '状态',
  `enterprise_id` bigint NOT NULL COMMENT '所属公司',
  `scrap_time` datetime NOT NULL COMMENT '报废时间',
  `scrap_explain` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '报废说明',
  `apply_user_id` bigint DEFAULT NULL COMMENT '申请人',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`scrap_id`) USING BTREE,
  KEY `index_apply_user` (`apply_user_id`) USING BTREE,
  KEY `idx_enterprise_id` (`enterprise_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

