-- ----------------------------
-- Table structure for t_bracket
-- ----------------------------
DROP TABLE IF EXISTS `t_bracket`;
CREATE TABLE `t_bracket` (
  `bracket_id` bigint NOT NULL AUTO_INCREMENT COMMENT '托架ID',
  `enterprise_id` bigint NOT NULL COMMENT '企业id',
  `business_mode` tinyint NOT NULL COMMENT '经营方式',
  `bracket_no` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '托架号',
  `manager_id` bigint DEFAULT NULL COMMENT '负责人',
  `shorthand_code` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '速记码',
  `weight` decimal(9,2) DEFAULT '0.00' COMMENT '重量',
  `tonnage` decimal(9,2) DEFAULT NULL COMMENT '载重',
  `type` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '型号',
  `nature` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '使用性质',
  `driving_license_pic` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '行驶证照片',
  `driving_license_attachment` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '行驶证附件',
  `issuing_organizations` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '发证机关',
  `register_time` datetime DEFAULT NULL COMMENT '注册日期',
  `issue_time` datetime DEFAULT NULL COMMENT '发证日期',
  `expire_time` datetime DEFAULT NULL COMMENT '到期日期',
  `driving_license_ectype_pic` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '行驶证副本',
  `driving_license_ectype_attachment` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '行驶证副本附件',
  `audit_status` int NOT NULL DEFAULT '1' COMMENT '审核状态1待审核 2审核通过 3驳回',
  `audit_remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '审核备注',
  `owner` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '所属人',
  `owner_type` int DEFAULT NULL COMMENT '所属人性质',
  `address` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '住址',
  `vin` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '车辆识别代码',
  `plate_color_code` int DEFAULT NULL COMMENT '车牌颜色代码',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '备注',
  `deleted_flag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除状态',
  `create_user_id` bigint NOT NULL COMMENT '创建人ID',
  `create_user_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '创建人名称',
  `create_user_type` tinyint NOT NULL COMMENT '创建人类型',
  `create_user_type_desc` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '创建人类型描述',
  `update_user_id` bigint DEFAULT NULL COMMENT '更新人ID',
  `update_user_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL,
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`bracket_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='托架表';

-- ----------------------------
-- Records of t_bracket
-- ----------------------------
BEGIN;
COMMIT;

