  `consumables_id` bigint unsigned NOT NULL COMMENT '耗材 ID',
  `location_id` bigint unsigned NOT NULL COMMENT '所属位置',
  `record_type` tinyint NOT NULL COMMENT '变更类型',
  `order_id` bigint NOT NULL COMMENT '单据id',
  `order_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '单据编码',
  `before_count` int NOT NULL DEFAULT '0' COMMENT '变动前库存数量',
