  `after_count` int NOT NULL DEFAULT '0' COMMENT '变动后库存数量',
  `before_average_price` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '变动前平均采购价',
  `price` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '本次采购单价',
  `after_average_price` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '变动后平均采购价',
  `remark` varchar(5000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备注',
  `create_user_id` bigint NOT NULL COMMENT '创建人id',
