  `contract_id` bigint NOT NULL AUTO_INCREMENT COMMENT '合同ID',
  `enterprise_id` bigint NOT NULL COMMENT '企业ID',
  `contract_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '合同编号',
  `contract_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '合同名称',
  `contract_type` int NOT NULL COMMENT '合同类型',
  `expiration_date` datetime DEFAULT NULL COMMENT '到期日期',
  `template_id` bigint DEFAULT NULL COMMENT '模板ID',
  `responsible_user_id` bigint DEFAULT NULL COMMENT '合同负责人',
  `sign_type` int NOT NULL COMMENT '合同签署类型 线上/线下',
  `contract_file` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '合同文件',
  `online_contract_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '线上签署合同ID',
  `signer_type` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '签署人类型（货主/车队/司机）\n',
  `signer_accounts_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '签署人账号ID（第三方）',
  `signer_belong_id` bigint DEFAULT NULL COMMENT '签署人归属ID（货主/车队/司机）',
  `order_id` bigint DEFAULT NULL COMMENT '订单ID',
  `order_no` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '订单编号',
  `waybill_id` bigint DEFAULT NULL COMMENT '运单ID',
  `waybill_number` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '运单号',
  `status` int NOT NULL COMMENT '合同状态',
  `remark` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '备注',
  `deleted_flag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除状态',
  `create_user_id` bigint NOT NULL COMMENT '创建人ID',
  `update_user_id` bigint NOT NULL COMMENT '更新人ID',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`contract_id`) USING BTREE,
  KEY `idx_enterprise_id` (`enterprise_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='合同管理';

-- ----------------------------
-- Records of t_contract
-- ----------------------------
BEGIN;
COMMIT;

