-- ----------------------------
-- Table structure for t_driver
-- ----------------------------
DROP TABLE IF EXISTS `t_driver`;
CREATE TABLE `t_driver` (
  `driver_id` bigint NOT NULL AUTO_INCREMENT,
  `enterprise_id` bigint NOT NULL COMMENT '企业id',
  `driver_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '司机姓名',
  `telephone` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '司机手机号',
  `business_mode` tinyint NOT NULL COMMENT '经营方式',
  `shorthand_code` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '速记码',
  `emergency_contact_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '紧急联系人姓名',
  `emergency_contact_phone` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '紧急联系人手机号',
  `home_address` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '家庭住址',
  `photo` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '照片',
  `national` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '民族',
  `gender` tinyint(1) DEFAULT '1' COMMENT '性别 0：女  1：男',
  `birthday` datetime DEFAULT NULL COMMENT '出生日期',
  `driving_license` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '身份证号',
  `id_card_front_pic` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '身份证国徽面图片',
  `id_card_back_pic` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '身份证人像面图片',
  `issue` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '签证机关',
  `id_card_endless_flag` tinyint(1) DEFAULT NULL COMMENT '身份证是否长期有效  0否  1是',
  `id_card_effective_start_date` datetime DEFAULT NULL COMMENT '身份证有效期开始日期',
  `id_card_effective_end_date` datetime DEFAULT NULL COMMENT '身份证有效期结束日期',
  `driving_license_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '驾驶证号',
  `driving_license_front_pic` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '驾驶证正本图',
  `driving_license_back_pic` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '驾驶证副本图',
  `license_first_get_date` datetime DEFAULT NULL COMMENT '首次驾照签发日期',
  `valid_period_from` datetime DEFAULT NULL COMMENT '驾驶证有效期自',
  `valid_period_to` datetime DEFAULT NULL COMMENT '驾驶证有效期至',
  `driving_license_endless_flag` tinyint(1) DEFAULT NULL COMMENT '驾驶证是否长期有效 0否1是',
  `vehicle_class` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '驾驶证准驾车型',
  `issuing_organizations` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '驾驶证发证机关',
  `qualification_certificate_pic` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '从业资格证图片',
  `qualification_certificate` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '从业资格证号',
  `qualification_certificate_start_date` datetime DEFAULT NULL COMMENT '从业资格证有效期自',
  `qualification_certificate_end_date` datetime DEFAULT NULL COMMENT '从业资格证有效期到',
  `manager_id` bigint DEFAULT NULL COMMENT '负责人ID',
  `remark` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备注',
  `status` int NOT NULL DEFAULT '1' COMMENT '状态 1激活2禁用',
  `audit_status` tinyint NOT NULL DEFAULT '1' COMMENT '审核状态 1待审核  2审核通过  3审核驳回',
  `audit_remark` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT '0' COMMENT '审核备注',
  `id_card_license_status` tinyint(1) NOT NULL DEFAULT '0' COMMENT '身份证证到期状态(默认 0未到期  1已到期)',
  `last_login_time` datetime DEFAULT NULL COMMENT '最后登录时间',
  `deleted_flag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除状态',
  `create_user_id` bigint NOT NULL COMMENT '创建人ID',
  `create_user_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `create_user_type` tinyint NOT NULL COMMENT '创建人类型',
