-- ----------------------------
-- Table structure for t_insurance
-- ----------------------------
DROP TABLE IF EXISTS `t_insurance`;
CREATE TABLE `t_insurance` (
  `insurance_id` bigint NOT NULL AUTO_INCREMENT COMMENT '保险ID',
  `enterprise_id` bigint NOT NULL COMMENT '所属企业id',
  `policy_number` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '保单号',
  `insurance_company_code` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '保险公司代码',
  `insurance_type` int NOT NULL COMMENT '保险类型',
  `module_id` bigint NOT NULL COMMENT '保险对象ID',
  `module_type` int NOT NULL COMMENT '保险对象类型 1车辆 2托架',
  `insurance_amount` decimal(11,2) NOT NULL COMMENT '保险金额',
  `policy_insurance_amount` decimal(11,2) NOT NULL COMMENT '保险单费用',
  `effect_date` date DEFAULT NULL COMMENT '投保时间',
  `expire_date` date NOT NULL COMMENT '有效期至',
  `attachment` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '附件',
  `enroll_date` date DEFAULT NULL COMMENT '登记日期',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '备注',
  `deleted_flag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除状态',
  `create_user_id` bigint NOT NULL COMMENT '创建人ID',
  `create_user_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `update_user_id` bigint DEFAULT NULL COMMENT '更新人ID',
  `update_user_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL,
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`insurance_id`) USING BTREE,
  KEY `idx_insurance_type` (`insurance_type`) USING BTREE,
  KEY `idx_module_id` (`module_id`) USING BTREE,
  KEY `idx_module_type` (`module_type`) USING BTREE,
  KEY `idx_enterprise` (`enterprise_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='保险表';

-- ----------------------------
-- Records of t_insurance
-- ----------------------------
BEGIN;
COMMIT;

