  `login_log_id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键',
  `enterprise_id` bigint NOT NULL COMMENT '企业id',
  `user_id` int NOT NULL COMMENT '用户id',
  `user_type` int NOT NULL COMMENT '用户类型',
