-- ----------------------------
-- Table structure for t_oil_card
-- ----------------------------
DROP TABLE IF EXISTS `t_oil_card`;
CREATE TABLE `t_oil_card` (
  `oil_card_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `master_oil_card_id` bigint NOT NULL DEFAULT '0' COMMENT '主卡ID',
  `oil_card_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '油卡号',
  `enterprise_id` bigint DEFAULT NULL COMMENT '所属公司',
  `type` tinyint NOT NULL COMMENT '类型',
  `fuel_type` tinyint NOT NULL COMMENT '燃料类型',
  `brand` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '品牌',
  `purpose` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '用途',
  `receive_user_id` bigint DEFAULT NULL COMMENT '领卡人',
  `use_driver_id` bigint DEFAULT NULL COMMENT '持卡人',
  `use_vehicle_id` bigint DEFAULT NULL COMMENT '持卡车',
  `use_time` datetime DEFAULT NULL COMMENT '持卡时间',
  `begin_balance` decimal(9,2) NOT NULL DEFAULT '0.00' COMMENT '期初余额',
  `balance` decimal(9,2) NOT NULL DEFAULT '0.00' COMMENT '余额',
  `pre_distribution_balance` decimal(9,2) NOT NULL DEFAULT '0.00' COMMENT '待分配金额',
  `pre_recharge_amount` decimal(9,2) NOT NULL DEFAULT '0.00' COMMENT '计划充值金额',
  `password` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '密码',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '备注',
  `fixed_point_flag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否定点加油',
  `disabled_flag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '禁用状态',
  `deleted_flag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除状态',
  `create_user_id` bigint NOT NULL COMMENT '创建人ID',
  `create_user_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '创建人',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`oil_card_id`) USING BTREE,
  KEY `idx_enterprise_id` (`enterprise_id`) USING BTREE,
  KEY `idx_type` (`type`) USING BTREE,
  KEY `idx_master_oil_card_id` (`master_oil_card_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='油卡表';

-- ----------------------------
-- Records of t_oil_card
-- ----------------------------
BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for t_oil_card_balance_record
-- ----------------------------
DROP TABLE IF EXISTS `t_oil_card_balance_record`;
CREATE TABLE `t_oil_card_balance_record` (
  `balance_record_id` bigint NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `balance_record_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '编号',
  `oil_card_id` bigint NOT NULL COMMENT '油卡ID',
  `oil_card_type` int NOT NULL COMMENT '油卡类型',
  `record_type` int NOT NULL DEFAULT '1' COMMENT '交易记录类型',
  `record_type_desc` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '交易记录类型',
  `before_balance` decimal(10,2) NOT NULL COMMENT '主卡变动前金额',
  `change_balance` decimal(10,2) NOT NULL COMMENT '主卡变动金额',
  `after_balance` decimal(10,2) NOT NULL COMMENT '主卡变动后金额',
  `related_record_id` bigint DEFAULT NULL COMMENT '影响的油卡ID',
  `remark` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '备注',
  `transaction_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '交易时间',
  `create_user_id` bigint NOT NULL COMMENT '创建人ID',
  `create_user_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '创建人',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`balance_record_id`) USING BTREE,
  KEY `idx_oil_card_id` (`oil_card_id`) USING BTREE,
  KEY `idx_oil_card_type` (`oil_card_type`) USING BTREE,
  KEY `idx_type` (`record_type`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='油卡金额变动表';

