-- ----------------------------
-- Table structure for t_pay_order
-- ----------------------------
DROP TABLE IF EXISTS `t_pay_order`;
CREATE TABLE `t_pay_order` (
  `pay_order_id` bigint NOT NULL AUTO_INCREMENT COMMENT '付款单id',
  `pay_order_number` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '付款单号',
  `order_id` bigint NOT NULL DEFAULT '0' COMMENT '订单id',
  `order_type` tinyint NOT NULL DEFAULT '0' COMMENT '单据类型 1普通 2网络 3安联',
  `nft_enterprise_id` bigint DEFAULT NULL COMMENT '网货企业id',
  `waybill_id` bigint NOT NULL COMMENT '运单id',
  `pay_order_type` tinyint NOT NULL COMMENT '付款单类型',
  `enterprise_id` bigint NOT NULL COMMENT '企业id',
  `shipper_id` bigint NOT NULL COMMENT '货主id',
  `driver_id` bigint NOT NULL COMMENT '司机id',
  `vehicle_id` bigint NOT NULL COMMENT '车辆id',
  `fleet_id` bigint DEFAULT NULL COMMENT '车队id',
  `oil_card_id` bigint DEFAULT NULL COMMENT '油卡id',
  `payable_total_amount` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '应付总金额',
  `paid_total_amount` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '已支付总金额',
  `attachment` varchar(500) DEFAULT NULL COMMENT '凭证附件',
  `sequence_code` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '交易流水号',
  `pay_time` datetime DEFAULT NULL COMMENT '付款时间',
  `audit_status` tinyint NOT NULL DEFAULT '1' COMMENT '审核状态',
  `pay_order_status` tinyint NOT NULL DEFAULT '10' COMMENT '付款单状态',
  `verification_flag` tinyint NOT NULL COMMENT '是否核销',
  `remark` varchar(2000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '备注',
  `flow_instance_id` bigint DEFAULT '0' COMMENT '审批流id',
  `create_user_id` bigint NOT NULL COMMENT '创建人',
  `create_user_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`pay_order_id`) USING BTREE,
  KEY `idx_verification_flag` (`verification_flag`) USING BTREE,
  KEY `idx_enterprise_id` (`enterprise_id`) USING BTREE,
  KEY `idx_driver_id` (`driver_id`),
  KEY `idx_vehicle_id` (`vehicle_id`),
  KEY `idx_status` (`pay_order_status`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

-- ----------------------------
-- Records of t_pay_order
-- ----------------------------
BEGIN;
COMMIT;

