-- ----------------------------
-- Table structure for t_receive_order
-- ----------------------------
DROP TABLE IF EXISTS `t_receive_order`;
CREATE TABLE `t_receive_order` (
  `receive_order_id` bigint NOT NULL AUTO_INCREMENT COMMENT '收款单ID',
  `receive_order_number` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '收款单号',
  `shipper_id` bigint NOT NULL COMMENT '货主ID',
  `enterprise_id` bigint NOT NULL COMMENT '订单所属公司',
  `make_invoice_flag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否需要开票',
  `total_amount` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '总金额',
  `tax_point` decimal(5,2) DEFAULT NULL COMMENT '税点',
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '备注',
  `account_period_date` datetime DEFAULT NULL COMMENT '账期',
  `check_status` int NOT NULL DEFAULT '1' COMMENT '对账状态，默认1',
  `check_user_id` bigint DEFAULT NULL COMMENT '对账人',
  `check_user_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '对账人名称',
  `check_attachment` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '对账凭证',
  `check_remark` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '对账备注',
  `check_time` datetime DEFAULT NULL COMMENT '对账时间',
  `invoice_status` int NOT NULL DEFAULT '1' COMMENT '开票状态，默认1',
  `verification_flag` tinyint NOT NULL DEFAULT '0' COMMENT '核销状态：默认0',
  `bill_attachment` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '上传对账单附件',
  `attachment` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '附件',
  `business_date` datetime DEFAULT NULL COMMENT '业务日期，账单月份',
  `deleted_flag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除状态',
  `create_user_id` bigint DEFAULT NULL COMMENT '创建人',
  `create_user_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '创建人',
  `update_user_id` bigint DEFAULT NULL COMMENT '更新人',
  `update_version` bigint NOT NULL DEFAULT '0' COMMENT '版本号',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP,
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (`receive_order_id`) USING BTREE,
  KEY `idx_shipper_id` (`shipper_id`) USING BTREE,
  KEY `idx_enterprise_id` (`enterprise_id`) USING BTREE,
  KEY `idx_check_status` (`check_status`) USING BTREE,
  KEY `idx_invoice_status` (`invoice_status`) USING BTREE,
  KEY `idx_verification_flag` (`verification_flag`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='应收帐款';

-- ----------------------------
-- Records of t_receive_order
-- ----------------------------
BEGIN;
COMMIT;

