BEGIN;
COMMIT;

-- ----------------------------
-- Table structure for t_shipper
-- ----------------------------
DROP TABLE IF EXISTS `t_shipper`;
CREATE TABLE `t_shipper` (
  `shipper_id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT 'id',
  `enterprise_id` bigint unsigned NOT NULL COMMENT '所属公司ID',
  `shipper_nature` tinyint NOT NULL DEFAULT '0' COMMENT '往来单位性质，0企业 1个人',
  `consignor` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '货主名称',
  `short_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '简称',
  `shipper_phone` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '往来机构电话',
  `access_key` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL,
  `tag_type` tinyint DEFAULT NULL COMMENT '标签',
  `grade` tinyint DEFAULT NULL COMMENT '等级',
  `fax` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '传真',
  `consignor_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '社会信用统一代码',
  `consignor_image` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '社会信用统一代码图片',
  `legal_person_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '法人',
  `legal_person_id_number` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '法人身份证号',
  `legal_person_phone` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '法人电话',
  `manager_id` bigint DEFAULT NULL COMMENT '负责人id',
  `customer_service_id` bigint DEFAULT NULL COMMENT '客服ID',
  `area` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '所在地区',
  `make_invoice_flag` tinyint unsigned NOT NULL DEFAULT '0' COMMENT '是否需要开票',
  `tax_point` decimal(6,3) unsigned NOT NULL DEFAULT '0.000' COMMENT '税点',
  `deduct_tax_flag` tinyint unsigned NOT NULL DEFAULT '0' COMMENT '是否扣税',
  `deduct_tax_ratio` decimal(5,2) unsigned NOT NULL DEFAULT '0.00' COMMENT '扣税比例',
  `account_period` int NOT NULL DEFAULT '0' COMMENT '账期',
  `address` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '详细地址',
  `remark` varchar(5000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备注',
  `attachment` varchar(5000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '附件',
  `verify_flag` tinyint DEFAULT '0' COMMENT '校验状态',
  `audit_status` int NOT NULL COMMENT '审核状态',
  `audit_remark` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备注',
  `mnemonic_code` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '助记码',
  `disable_flag` tinyint NOT NULL DEFAULT '0' COMMENT '禁用状态',
  `deleted_flag` tinyint unsigned NOT NULL DEFAULT '0' COMMENT '删除状态',
  `create_user_id` bigint NOT NULL COMMENT '创建人id',
  `create_user_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`shipper_id`) USING BTREE,
  KEY `manager_id` (`manager_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='货主';

-- ----------------------------
-- Records of t_shipper
-- ----------------------------
BEGIN;
COMMIT;

