-- ----------------------------
-- Table structure for t_shipper_track
-- ----------------------------
DROP TABLE IF EXISTS `t_shipper_track`;
CREATE TABLE `t_shipper_track` (
  `track_id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `employee_id` bigint NOT NULL COMMENT '员工id',
  `shipper_id` bigint NOT NULL COMMENT '货主ID',
  `track_way` tinyint(1) NOT NULL COMMENT '跟进方式',
  `interviewee_name` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '被拜访人名称',
  `track_time` datetime NOT NULL COMMENT '跟进时间',
  `track_content` varchar(5000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '跟进内容',
  `next_track_time` datetime DEFAULT NULL COMMENT '下次跟进时间',
  `remark` varchar(5000) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '备注',
  `attachment` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci DEFAULT NULL COMMENT '附件',
  `ip` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'ip',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`track_id`) USING BTREE,
  KEY `idx_contact_company_id` (`shipper_id`) USING BTREE,
  KEY `idx_employee_id` (`employee_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci COMMENT='货主跟进记录表';

-- ----------------------------
-- Records of t_shipper_track
