DROP TABLE IF EXISTS `t_sms_record`;
CREATE TABLE `t_sms_record` (
  `record_id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `sms_type` tinyint NOT NULL COMMENT '短信类型 ',
  `sms_type_desc` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '短信类型说明',
  `sms_sub_type` tinyint NOT NULL COMMENT '短信子类型',
  `sms_sub_type_desc` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '短信子类型说明',
  `content` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '短信内容',
  `extra_data` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '额外数据',
  `phone` varchar(11) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '手机号',
  `service_record_id` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '服务商id',
  `success_flag` tinyint(1) NOT NULL COMMENT '是否成功',
  `receive_time` datetime DEFAULT NULL COMMENT '接收时间',
  `error_msg` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL,
