-- ----------------------------
-- Table structure for t_vehicle
-- ----------------------------
DROP TABLE IF EXISTS `t_vehicle`;
CREATE TABLE `t_vehicle` (
  `vehicle_id` bigint NOT NULL AUTO_INCREMENT COMMENT '车辆ID',
  `enterprise_id` bigint NOT NULL COMMENT '企业id',
  `business_mode` tinyint NOT NULL COMMENT '经营方式',
  `shorthand` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '速记码',
  `vehicle_number` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '车牌号',
  `province` int DEFAULT NULL,
  `province_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL,
  `city` int DEFAULT NULL,
  `city_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL,
  `district` int DEFAULT NULL COMMENT '车籍地地区编码',
  `district_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '车籍地地区名称',
  `vehicle_plate_color_code` int DEFAULT NULL COMMENT '车牌颜色代码',
  `vehicle_type` varchar(35) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '车辆类型代码',
  `gross_mass` decimal(9,2) DEFAULT '0.00' COMMENT '总质量',
  `vehicle_tonnage` decimal(9,2) DEFAULT '0.00' COMMENT '核定载质量',
  `curb_weight` decimal(9,2) NOT NULL DEFAULT '0.00' COMMENT '整备质量',
  `traction_weight` decimal(9,2) NOT NULL DEFAULT '0.00' COMMENT '准牵引质量',
  `gabarite` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '外廓尺寸',
  `owner` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '所属人',
  `owner_type` int DEFAULT NULL COMMENT '所属人性质',
  `vin` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '车辆识别代码',
  `license_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '车辆行驶证档案编号',
  `nature` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '使用性质',
  `engine_number` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '发动机号',
  `vehicle_registration_certificate_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '机动车登记证书编号',
  `vehicle_energy_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '车辆能源类型',
  `bracket_id` bigint DEFAULT NULL COMMENT '托架车号',
  `driving_license_attachment` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '行驶证附件',
  `issuing_organizations` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '发证机关',
  `register_date` datetime DEFAULT NULL COMMENT '行驶证注册日期',
  `issue_date` datetime DEFAULT NULL COMMENT '行驶证发证日期',
  `expire_date` datetime DEFAULT NULL COMMENT '行驶证到期日期',
  `driving_license_ectype_attachment` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '副本附件',
  `road_transport_certificate_number` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '道路运输证号',
  `road_transport_certificate_attachment` text CHARACTER SET utf16le COLLATE utf16le_general_ci COMMENT '道路运输证附件',
  `road_transport_business_license_number` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '道路运输经营许可证号',
  `road_transport_certificate_expire_date` datetime DEFAULT NULL COMMENT '道路运输证到期时间',
  `road_transport_certificate_start_date` datetime DEFAULT NULL COMMENT '道运证有效期开始日期',
  `vehicle_audit_expire_date` datetime DEFAULT NULL COMMENT '车辆审验到期时间',
  `rely_enterprise_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '挂靠企业名称',
  `rely_enterprise_attachment` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '挂靠企业协议附件',
  `rely_enterprise_expire_date` datetime DEFAULT NULL COMMENT '挂靠到期时间',
  `rely_enterprise_business_license_attachment` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '挂靠企业营业执照-附件',
  `rely_enterprise_unified_social_credit_code` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '挂靠企业营业统一社会信用代码',
  `rely_enterprise_road_transport_business_license_number` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '挂靠企业-道路运输经营许可证号',
  `rely_enterprise_road_transport_business_license_attachment` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '挂靠企业-道路运输经营许可证附件',
  `rely_enterprise_road_transport_business_license_issue_date` datetime DEFAULT NULL COMMENT '挂靠企业-道路运输经营许可证-发证日期',
  `rely_enterprise_road_transport_business_license_expire_date` datetime DEFAULT NULL COMMENT '挂靠企业-道路运输经营许可证-结束日期',
  `manager_id` bigint DEFAULT NULL COMMENT '负责人ID',
  `model` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '品牌型号',
  `receive_user_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '收款人姓名',
  `receive_bank_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '收款人银行',
  `receive_bank_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '收款人银行账号',
  `remark` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '备注',
  `audit_remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '审核备注',
  `audit_status` tinyint NOT NULL DEFAULT '1' COMMENT '审核状态 1待审核  2审核通过  3审核驳回',
  `disabled_flag` tinyint NOT NULL DEFAULT '0' COMMENT '禁用状态：0没禁用，1禁用',
  `deleted_flag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '删除状态',
  `create_user_id` bigint NOT NULL COMMENT '创建人ID',
  `create_user_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL,
  `create_user_type` tinyint NOT NULL COMMENT '创建人类型',
  `create_user_type_desc` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '创建人类型描述',
  `update_user_id` bigint DEFAULT NULL COMMENT '更新人ID',
  `update_user_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL,
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  PRIMARY KEY (`vehicle_id`) USING BTREE,
  KEY `vehicle_type_index` (`vehicle_type`) USING BTREE,
  KEY `idx_enterprise_id` (`enterprise_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='车辆表';

-- ----------------------------
-- Records of t_vehicle
-- ----------------------------
BEGIN;
COMMIT;

