-- ----------------------------
-- Table structure for t_waybill
-- ----------------------------
DROP TABLE IF EXISTS `t_waybill`;
CREATE TABLE `t_waybill` (
  `waybill_id` bigint NOT NULL AUTO_INCREMENT COMMENT '运单自增id',
  `waybill_number` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '运单号',
  `split_transport_flag` tinyint NOT NULL DEFAULT '0' COMMENT '是否分段运输',
  `order_id` bigint NOT NULL COMMENT '订单id',
  `shipper_id` bigint NOT NULL COMMENT '货主id',
  `enterprise_id` bigint NOT NULL COMMENT '企业id',
  `order_type` tinyint NOT NULL DEFAULT '0' COMMENT '运单类型 1普通 2网路 3安联',
  `tax_point` decimal(20,4) NOT NULL DEFAULT '4.0000' COMMENT '税点',
  `nft_enterprise_id` bigint DEFAULT NULL COMMENT '网路货运企业id',
  `lead_seal_number` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '铅封',
  `container_number` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '集装箱号',
  `waybill_status` int NOT NULL DEFAULT '10' COMMENT '运单状态',
  `audit_status` int NOT NULL DEFAULT '1' COMMENT '审核状态',
  `settle_type` tinyint NOT NULL COMMENT '结算类型 10司机 20车队',
  `settle_mode` tinyint DEFAULT NULL COMMENT '结算方式 10到付 20月结',
  `driver_id` bigint NOT NULL COMMENT '司机',
  `vehicle_id` bigint NOT NULL COMMENT '车辆id',
  `fleet_id` bigint DEFAULT NULL COMMENT '车队id',
  `submit_receive_flag` tinyint NOT NULL DEFAULT '0' COMMENT '是否提交应收核算',
  `receive_amount` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '应收总金额',
  `payable_amount` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '应付总金额',
  `salary_amount` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '工资',
  `car_cost_amount` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '车辆费用',
  `paid_amount` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '已支付金额',
  `profit_amount` decimal(20,4) DEFAULT NULL COMMENT '利润金额',
  `payable_cash_amount` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '应付现金金额',
  `cash_pay_status` tinyint NOT NULL DEFAULT '0' COMMENT '现金付款状态',
  `payable_oil_card_amount` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '应付油卡金额',
  `oil_card_pay_status` tinyint NOT NULL DEFAULT '0' COMMENT '油卡付款状态',
  `pay_status` tinyint NOT NULL DEFAULT '0' COMMENT '付款状态',
  `remark` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '备注',
  `deliver_goods_time` datetime DEFAULT NULL COMMENT '发货时间',
  `receive_goods_time` datetime DEFAULT NULL COMMENT '收货时间',
  `load_pound_list_quantity` decimal(20,3) DEFAULT NULL COMMENT '装货磅单重量',
  `unload_pound_list_quantity` decimal(20,3) DEFAULT NULL COMMENT '卸货磅单重量',
  `sign_pound_list_quantity` decimal(20,3) DEFAULT NULL COMMENT '签收磅单重量',
  `load_time` datetime NOT NULL COMMENT '装/卸货时间',
  `unload_time` datetime DEFAULT NULL COMMENT '卸货时间',
  `complete_time` datetime DEFAULT NULL COMMENT '完成时间',
  `route_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '路线名字',
  `distance` bigint NOT NULL DEFAULT '0' COMMENT '运输距离',
  `receipt_attachment` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '回单',
  `truck_order_attachment` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '派车单',
  `business_date` datetime DEFAULT NULL COMMENT '业务日期，账单月份',
  `transport_mode` int NOT NULL DEFAULT '0' COMMENT '运输方式 10长途 20短驳内部 30短驳外部',
  `flow_instance_id` bigint DEFAULT NULL COMMENT '流程实例id',
  `create_user_id` bigint NOT NULL COMMENT '创建人',
  `create_user_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '创建人名称',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`waybill_id`) USING BTREE,
  UNIQUE KEY `uk_waybill_number` (`waybill_number`) USING BTREE,
  KEY `idx_enterprise_id` (`enterprise_id`) USING BTREE,
  KEY `idx_driver_id` (`driver_id`) USING BTREE,
  KEY `idx_vehicle_id` (`vehicle_id`) USING BTREE,
  KEY `idx_order_type` (`order_type`) USING BTREE,
  KEY `idx_waybill_status` (`waybill_status`) USING BTREE,
  KEY `idx_shipper_id` (`shipper_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;

-- ----------------------------
-- Records of t_waybill
-- ----------------------------
BEGIN;
COMMIT;

