-- ----------------------------
-- Table structure for t_waybill_oil_card_recharge_apply
-- ----------------------------
DROP TABLE IF EXISTS `t_waybill_oil_card_recharge_apply`;
CREATE TABLE `t_waybill_oil_card_recharge_apply` (
  `recharge_apply_id` bigint NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `recharge_apply_no` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '充值单号',
  `order_type` tinyint NOT NULL COMMENT '单据类型',
  `enterprise_id` bigint NOT NULL COMMENT '企业id',
  `nft_enterprise_id` bigint NOT NULL DEFAULT '0' COMMENT '网货企业id',
  `master_oil_card_enterprise_id` bigint NOT NULL COMMENT '油卡主卡的所属公司',
  `oil_card_id` bigint NOT NULL COMMENT '油卡ID',
  `oil_card_no` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '油卡卡号',
  `waybill_id` bigint NOT NULL COMMENT '运单ID',
  `driver_id` bigint NOT NULL COMMENT '司机id',
  `vehicle_id` bigint NOT NULL COMMENT '车辆id',
  `amount` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '充值金额',
  `nft_amount` decimal(20,4) NOT NULL DEFAULT '0.0000' COMMENT '网络货运费',
  `verification_flag` tinyint NOT NULL DEFAULT '0' COMMENT '是否核销',
  `verification_attachment` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '核销附件',
  `verification_remark` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '核销备注',
  `verification_user_id` bigint DEFAULT NULL COMMENT '核销人',
  `verification_user_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '核销人名称',
  `verification_time` datetime DEFAULT NULL COMMENT '核销时间',
  `recharge_flag` tinyint NOT NULL DEFAULT '0' COMMENT '是否充值',
  `recharge_attachment` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '充值附件',
  `recharge_user_id` bigint DEFAULT NULL COMMENT '充值人',
  `recharge_user_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '充值人名称',
  `recharge_time` datetime DEFAULT NULL COMMENT '充值时间',
  `remark` varchar(2000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '备注',
  `audit_status` int NOT NULL DEFAULT '1' COMMENT '审核状态',
  `flow_instance_id` bigint DEFAULT NULL COMMENT '流程实例id',
  `add_pre_distribution_balance_flag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否增加油卡预分配金额',
  `reduce_pre_distribution_balance_flag` tinyint(1) NOT NULL DEFAULT '0' COMMENT '是否减少油卡预分配金额',
  `disabled_flag` tinyint NOT NULL DEFAULT '0' COMMENT '是否作废',
  `disabled_remark` varchar(2000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '作废备注',
  `create_user_id` bigint NOT NULL COMMENT '创建人ID',
  `create_user_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '创建人',
  `update_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `create_time` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `master_oil_card_id` bigint DEFAULT NULL COMMENT '油卡主卡ID',
  `master_oil_card_no` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '油卡主卡卡号',
  `master_oil_card_enterprise_name` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '油卡主卡公司名称',
  `oil_card_nft_flag` tinyint NOT NULL DEFAULT '0' COMMENT '是否选择了中邦油卡',
  PRIMARY KEY (`recharge_apply_id`) USING BTREE,
  KEY `idx_waybill_id` (`waybill_id`) USING BTREE,
  KEY `idx_oil_card_id` (`oil_card_id`) USING BTREE,
  KEY `idx_driver_id` (`driver_id`) USING BTREE,
  KEY `idx_vehicle_id` (`vehicle_id`) USING BTREE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='油卡充值表';

